sections.code_example:
# break: find the first even number and stop
for n in range(1, 10):
    if n % 2 == 0:
        print("First even number:", n)
        break

print("---")

# continue: print only odd numbers
for n in range(1, 8):
    if n % 2 == 0:
        continue          # skip even numbers
    print(n)

# pass as a placeholder in a conditional
for n in range(1, 6):
    if n == 3:
        pass    # TODO: handle the special case later
    else:
        print(n)

print("---")

# Contrast with continue: skip silently
for n in range(1, 6):
    if n == 3:
        continue
    print(n)

